noncompliant:
void f(int i, int j);

void g() {
  int i = 0;
  f(++i, ++i); // Noncompliant, the call could either be f(1,2) or f(2,1) (since C++17) or undefined behavior (before C++17)
}

void process(int a, int b, int c);

void test() {
  int x = 5;
  process(x++, x++, x++); // Noncompliant: multiple modifications of x in arguments
}

int getValue();
int global = 0;

void func(int a, int b) {
  printf("%d %d\n", ++global, getValue()); // Noncompliant if getValue() modifies global
}

compliant:
void f(int i, int j);

void g() {
  int i = 0;
  ++i;
  ++i;
  f(i, i); // Compliant: modifications done before function call
}

void process(int a, int b, int c);

void test() {
  int x = 5;
  int a = ++x;
  int b = ++x;
  int c = ++x;
  process(a, b, c); // Compliant: separate statements
}

void func(int a, int b) {
  int temp1 = ++global;
  int temp2 = getValue();
  printf("%d %d\n", temp1, temp2); // Compliant: separate evaluation
}
